import type * as DMMF from '@prisma/dmmf'

import { scalarTypeToTs } from './render-typescript-type'

/** Returns true for fields that map to a concrete column (scalars + enums). */
function isScalarField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/**
 * Returns true when the field's value is always supplied by the database or
 * the Prisma runtime so the caller does not need to provide it on creation.
 * This covers auto-increment IDs, uuid/cuid defaults, and @updatedAt.
 */
function isAutoGenerated(field: DMMF.Field): boolean {
  return field.isUpdatedAt === true || field.hasDefaultValue
}

function renderField(field: DMMF.Field, optional: boolean): string {
  const tsType = scalarTypeToTs(field.type)
  const listSuffix = field.isList ? '[]' : ''
  const optionalMark = optional || !field.isRequired ? '?' : ''
  return `  ${field.name}${optionalMark}: ${tsType}${listSuffix}`
}

/**
 * Renders the five TypeScript interfaces generated for a single Prisma model:
 * the base record shape, and the input shapes for create, update, whereUnique
 * and where (filter) operations.
 */
export function renderModelInterfaces(model: DMMF.Model): string {
  const scalarFields = model.fields.filter(isScalarField)
  const lines: string[] = []

  // Full record shape.
  lines.push(`export interface ${model.name} {`)
  for (const field of scalarFields) {
    lines.push(renderField(field, false))
  }
  lines.push('}', '')

  // Shape for create operations – auto-generated fields are omitted entirely
  // because the server supplies them.
  lines.push(`export interface ${model.name}CreateInput {`)
  for (const field of scalarFields) {
    if (!isAutoGenerated(field)) {
      lines.push(renderField(field, false))
    }
  }
  lines.push('}', '')

  // Shape for update operations – every writable field is optional because
  // callers only need to supply the fields they wish to change.
  lines.push(`export interface ${model.name}UpdateInput {`)
  for (const field of scalarFields) {
    if (!isAutoGenerated(field)) {
      lines.push(renderField(field, true))
    }
  }
  lines.push('}', '')

  // Unique lookup shape – only @id and @unique fields.
  const uniqueFields = scalarFields.filter((f) => f.isId || f.isUnique)
  lines.push(`export interface ${model.name}WhereUniqueInput {`)
  for (const field of uniqueFields) {
    lines.push(renderField(field, true))
  }
  lines.push('}', '')

  // Filter shape for list operations – every scalar field, all optional.
  lines.push(`export interface ${model.name}WhereInput {`)
  for (const field of scalarFields) {
    lines.push(renderField(field, true))
  }
  lines.push('}', '')

  // Sort shape – any field can be sorted ascending or descending.
  lines.push(`export type ${model.name}OrderByInput = {`)
  lines.push(`  [K in keyof ${model.name}]?: 'asc' | 'desc'`)
  lines.push('}', '')

  return lines.join('\n')
}

