import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { renderModelClient } from './render-model-client'
import { renderModelInterfaces } from './render-model-interfaces'

export type GenerateRestClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Generates a single `index.ts` file inside `outputDir` containing:
 *
 * - A TypeScript union type for every Prisma enum.
 * - Six TypeScript interfaces per model (base record, CreateInput, UpdateInput,
 *   WhereUniqueInput, WhereInput, OrderByInput).
 * - A typed REST client class per model with findMany / findUnique / create /
 *   update / delete methods.
 * - A top-level `RestApiClient` that aggregates all per-model clients and is
 *   the main entry-point for consumers.
 */
export async function generateRestClient({ dmmf, outputDir }: GenerateRestClientOptions): Promise<void> {
  const models = dmmf.datamodel.models
  const sections: string[] = [
    '// This file was auto-generated by @prisma/rest-api-generator. Do not edit manually.',
    '',
  ]

  // Enum union types must come first so model interfaces can reference them.
  for (const enumDef of dmmf.datamodel.enums) {
    const members = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
    sections.push(`export type ${enumDef.name} = ${members}`, '')
  }

  // Per-model interfaces and REST client classes.
  for (const model of models) {
    sections.push(renderModelInterfaces(model))
    sections.push(renderModelClient(model))
  }

  // Top-level aggregate client.
  sections.push('export class RestApiClient {')
  for (const model of models) {
    sections.push(`  readonly ${lowerFirst(model.name)}: ${model.name}RestClient`)
  }
  sections.push('')
  sections.push('  constructor(baseUrl: string) {')
  for (const model of models) {
    const prop = lowerFirst(model.name)
    sections.push(`    this.${prop} = new ${model.name}RestClient(baseUrl)`)
  }
  sections.push('  }')
  sections.push('}', '')

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'index.ts'), sections.join('\n'), 'utf-8')
}

