import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { generateRestClient } from './generate-rest-client'

/**
 * Prisma generator that produces a typed TypeScript REST API client from the
 * Prisma schema's DMMF.  Register it in `prisma.config.ts` (or `schema.prisma`)
 * using the provider name `"rest-api-client"`.
 *
 * @example
 * ```prisma
 * generator restClient {
 *   provider = "rest-api-client"
 *   output   = "./generated/rest-client"
 * }
