import os from 'node:os'
import path from 'node:path'
import fs from 'node:fs/promises'

import type * as DMMF from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateRestClient } from './generate-rest-client'
import { renderModelInterfaces } from './render-model-interfaces'
import { renderModelClient } from './render-model-client'
import { scalarTypeToTs } from './render-typescript-type'

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  primaryKey: null,
  uniqueFields: [],
  uniqueIndexes: [],
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'name',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'createdAt',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'DateTime',
      hasDefaultValue: true,
      default: { name: 'now', args: [] },
      isUpdatedAt: false,
    },
  ],
}

const roleEnum: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
  ],
}

const minimalDmmf: DMMF.Document = {
  datamodel: {
    models: [userModel],
    enums: [roleEnum],
    types: [],
    indexes: [],
  },
  schema: {
    inputObjectTypes: { prisma: [], model: [] },
    outputObjectTypes: { prisma: [], model: [] },
    enumTypes: { prisma: [], model: [] },
    fieldRefTypes: { prisma: [] },
  },
  mappings: {
    modelOperations: [],
    otherOperations: { read: [], write: [] },
  },
}

// ---------------------------------------------------------------------------
// scalarTypeToTs
// ---------------------------------------------------------------------------

describe('scalarTypeToTs', () => {
  it('maps Prisma scalar types to TypeScript primitives', () => {
    expect(scalarTypeToTs('String')).toBe('string')
    expect(scalarTypeToTs('Boolean')).toBe('boolean')
    expect(scalarTypeToTs('Int')).toBe('number')
    expect(scalarTypeToTs('Float')).toBe('number')
    expect(scalarTypeToTs('Decimal')).toBe('number')
    expect(scalarTypeToTs('BigInt')).toBe('bigint')
    expect(scalarTypeToTs('DateTime')).toBe('string')
    expect(scalarTypeToTs('Json')).toBe('unknown')
    expect(scalarTypeToTs('Bytes')).toBe('string')
  })

  it('passes enum and unknown types through unchanged', () => {
    expect(scalarTypeToTs('Role')).toBe('Role')
    expect(scalarTypeToTs('SomeFutureType')).toBe('SomeFutureType')
  })
})

// ---------------------------------------------------------------------------
// renderModelInterfaces
// ---------------------------------------------------------------------------

describe('renderModelInterfaces', () => {
  it('generates the base interface with all scalar fields', () => {
    const output = renderModelInterfaces(userModel)
    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name?: string')
    expect(output).toContain('  createdAt: string')
  })

  it('omits auto-generated fields from CreateInput', () => {
    const output = renderModelInterfaces(userModel)
    expect(output).toContain('export interface UserCreateInput {')
    // id (autoincrement) and createdAt (now default) are auto-generated.
    expect(output).not.toMatch(/UserCreateInput \{[^}]*\bid:/)
    expect(output).not.toMatch(/UserCreateInput \{[^}]*\bcreatedAt:/)
    expect(output).toContain('  email: string')
  })

  it('makes all fields optional in UpdateInput', () => {
    const output = renderModelInterfaces(userModel)
    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toContain('  email?: string')
    expect(output).toContain('  name?: string')
  })

  it('includes only @id and @unique fields in WhereUniqueInput', () => {
    const output = renderModelInterfaces(userModel)
    expect(output).toContain('export interface UserWhereUniqueInput {')
    expect(output).toContain('  id?: number')
    expect(output).toContain('  email?: string')
    // Non-unique field must not appear in WhereUniqueInput.
    expect(output).not.toMatch(/WhereUniqueInput \{[^}]*\bname:/)
  })

  it('includes all scalar fields in WhereInput', () => {
    const output = renderModelInterfaces(userModel)
    expect(output).toContain('export interface UserWhereInput {')
    expect(output).toContain('  id?: number')
    expect(output).toContain('  email?: string')
    expect(output).toContain('  name?: string')
  })

  it('generates the OrderByInput mapped type', () => {
    const output = renderModelInterfaces(userModel)
    expect(output).toContain("export type UserOrderByInput = {")
    expect(output).toContain("[K in keyof User]?: 'asc' | 'desc'")
  })
})

// ---------------------------------------------------------------------------
// renderModelClient
// ---------------------------------------------------------------------------

describe('renderModelClient', () => {
  it('generates a class with the correct name', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('export class UserRestClient {')
  })

  it('includes all five CRUD methods', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  it('references the correct input types', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('UserWhereInput')
    expect(output).toContain('UserWhereUniqueInput')
    expect(output).toContain('UserCreateInput')
    expect(output).toContain('UserUpdateInput')
  })

  it('uses lowercase resource name in URL paths', () => {
    const output = renderModelClient(userModel)
    // The resource segment should be the lowercased model name.
    expect(output).toContain('`${this.#baseUrl}/user`')
    expect(output).toContain('`${this.#baseUrl}/user/unique`')
  })

  it('uses correct HTTP verbs', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain("method: 'POST'")
    expect(output).toContain("method: 'PATCH'")
    expect(output).toContain("method: 'DELETE'")
    // findMany and findUnique use GET (no explicit method → default GET).
    expect(output).not.toMatch(/method:\s*'GET'/)
  })
})

// ---------------------------------------------------------------------------
// generateRestClient (integration)
// ---------------------------------------------------------------------------

describe('generateRestClient', () => {
  it('writes an index.ts file to the output directory', async () => {
    const outputDir = path.join(os.tmpdir(), `rest-api-gen-test-${Date.now()}`)
    await generateRestClient({ dmmf: minimalDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')

    // Auto-generated header.
    expect(content).toContain('auto-generated by @prisma/rest-api-generator')

    // Enum union type.
    expect(content).toContain("export type Role = 'ADMIN' | 'USER'")

    // Model interfaces.
    expect(content).toContain('export interface User {')
    expect(content).toContain('export interface UserCreateInput {')

    // Model REST client class.
    expect(content).toContain('export class UserRestClient {')

    // Top-level aggregate client.
    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('readonly user: UserRestClient')
    expect(content).toContain('this.user = new UserRestClient(baseUrl)')

    await fs.rm(outputDir, { recursive: true })
  })

  it('creates the output directory if it does not exist', async () => {
    const outputDir = path.join(os.tmpdir(), `rest-api-gen-test-nested-${Date.now()}`, 'deep', 'path')
    await generateRestClient({ dmmf: minimalDmmf, outputDir })
    await expect(fs.access(path.join(outputDir, 'index.ts'))).resolves.toBeUndefined()
    await fs.rm(path.join(os.tmpdir(), path.relative(os.tmpdir(), outputDir).split(path.sep)[0]), { recursive: true })
  })
})

